#nullable enable // autogenerated

using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Entities;
using PVZEngine.Definitions;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.napstablook_Animation)]
    public class Napstablook_AnimationBehaviour : EnemyCommonAnimationBehaviour
    {
        public Napstablook_AnimationBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        public override int GetAnimationState(int state)
        {
            switch (state)
            {
                case STATE_ANGRY:
                    return ANIMATION_STATE_ANGRY;
            }
            return base.GetAnimationState(state);
        }
        public const int STATE_ANGRY = VanillaEnemyStates.NAPSTABLOOK_ANGRY;
        public const int ANIMATION_STATE_ANGRY = EnemyCommonAnimationBehaviour.ANIMATION_STATE_PRIVATE + 0;
    }
}
